const https = require('https');
const http = require('http');
const { JSDOM } = require('jsdom');

const ALLOWED_DOMAINS = ['example.com', 'another-example.com']; // Add allowed domains here

function isValidUrl(url) {
    try {
        const parsedUrl = new URL(url);
        const domain = parsedUrl.hostname;

        // Check if the domain is in the allowlist
        if (!ALLOWED_DOMAINS.includes(domain)) {
            return false;
        }

        // Check for private IP addresses
        const ip = parsedUrl.hostname;
        const privateIpRegex = /^(10|172\.16|192\.168|169\.254|127\.0\.0\.1)/;
        if (privateIpRegex.test(ip)) {
            return false;
        }

        return true;
    } catch (error) {
        return false;
    }
}

async function fetchMetadata(url) {
    if (!isValidUrl(url)) {
        throw new Error('Invalid URL');
    }

    return new Promise((resolve, reject) => {
        const client = url.startsWith('https') ? https : http;

        client.get(url, (response) => {
            let data = '';

            response.on('data', (chunk) => {
                data += chunk;
            });

            response.on('end', () => {
                const dom = new JSDOM(data);
                const document = dom.window.document;

                const title = document.querySelector('title') ? document.querySelector('title').textContent : '';
                const description = document.querySelector('meta[name="description"]') ? document.querySelector('meta[name="description"]').content : '';
                const ogTags = Array.from(document.querySelectorAll('meta[property^="og:"]')).reduce((acc, meta) => {
                    acc[meta.getAttribute('property')] = meta.getAttribute('content');
                    return acc;
                }, {});

                resolve({ title, description, ogTags });
            });
        }).on('error', (err) => {
            reject(err);
        });
    });
}

exports.fetchUrlMetadata = async (req, res) => {
    const { url } = req.query;

    try {
        const metadata = await fetchMetadata(url);
        res.status(200).json(metadata);
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
};